// src/hooks/useAuth.ts
// ─── Firebase-aware auth hook ──────────────────────────────────────────────────
// Drop-in replacement for the original localStorage-based useAuth.
// Now reads from Firebase Auth + Firestore profile.

import { useState, useEffect } from "react";
import { getUserProfile, onAuthStateChange } from "../firebase/auth";
import type { AppUser, UserRole } from "../types";

export interface AuthState {
  user:            AppUser | null;
  loading:         boolean;
  isAuthenticated: boolean;
  role:            UserRole | null;
  isSuperAdmin:    boolean;
  isProprietario:  boolean;
  isMotorista:     boolean;
  isUsuario:       boolean;
}

export function useAuth(): AuthState {
  const [user,    setUser]    = useState<AppUser | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const unsubscribe = onAuthStateChange(async (firebaseUser) => {
      if (firebaseUser && (firebaseUser as any).uid) {
        const profile = await getUserProfile((firebaseUser as any).uid);
        setUser(profile);
      } else {
        setUser(null);
      }
      setLoading(false);
    });

    return unsubscribe;
  }, []);

  const role = user?.role ?? null;

  return {
    user,
    loading,
    isAuthenticated: !!user,
    role,
    isSuperAdmin:   role === "superadmin",
    isProprietario: role === "proprietario",
    isMotorista:    role === "motorista",
    isUsuario:      role === "usuario",
  };
}
