// Simple localStorage-backed faux Firestore for local development and tests.
type RecordAny = { id?: string; [k: string]: any };

function createDB(name: string) {
  const key = `db_${name}`;
  function read(): RecordAny[] {
    try { return JSON.parse(localStorage.getItem(key) || "[]"); } catch { return []; }
  }
  function write(data: RecordAny[]) { localStorage.setItem(key, JSON.stringify(data)); }

  return {
    getAll: () => read(),
    getById: (id: string) => read().find((r) => r.id === id) ?? null,
    add: (data: RecordAny) => {
      const all = read();
      const id = data.id ?? `id${Date.now()}`;
      const item = { ...data, id };
      all.push(item); write(all); return item;
    },
    update: (id: string, data: RecordAny) => {
      const all = read();
      const idx = all.findIndex((r) => r.id === id);
      if (idx === -1) return null;
      all[idx] = { ...all[idx], ...data, id };
      write(all); return all[idx];
    },
    remove: (id: string) => {
      const all = read();
      const out = all.filter((r) => r.id !== id);
      write(out); return true;
    },
    set: (id: string, data: RecordAny) => {
      const all = read();
      const idx = all.findIndex((r) => r.id === id);
      const item = { ...data, id };
      if (idx === -1) all.push(item); else all[idx] = item;
      write(all); return item;
    },
    // helpers used by servicos/veiculos
    getByProprietario: (propId: string) => read().filter((r) => r.proprietarioId === propId),
    getByUsuario: (uid: string) => read().filter((r) => r.usuarioId === uid || r.usuarioId === uid),
    getByViatura: (vid: string) => read().filter((r) => r.viaturaId === vid || r.viaturaId === vid),
    getAtivos: () => read().filter((r) => r.status === "em_andamento" || r.status === "ativo"),
    getFinalizados: () => read().filter((r) => r.status === "finalizado"),
  } as any;
}

export const usersDB = createDB("users");
export const viaturasDB = createDB("viaturas");
export const motoristasDB = createDB("motoristas");
export const proprietariosDB = createDB("proprietarios");
export const servicosDB = createDB("servicos");
export const transacoesDB = createDB("transacoes");
export const usuariosClientesDB = createDB("usuariosClientes");
export const rotasDB = createDB("rotas");
