export const alugueresStore = {
  getAll: () => {
    const servicos = servicosDB.getAll();
    return servicos.map((s: any) => ({
      ...s,
      clienteNome: s.clienteNome ?? "",
      veiculoId: s.viaturaId,
      dataInicio: s.dataInicio ?? "",
      dataFimPrevista: s.dataFimPrevista ?? "",
      status: s.status === "em_andamento" ? "ativo" : s.status === "finalizado" ? "concluido" : "cancelado",
    }));
  },
  add: (data: any) => {
    const valorTotal = data.valorTotal ?? 0;
    return servicosDB.add({
      ...data,
      viaturaId: data.veiculoId ?? data.viaturaId,
      tipo: data.tipo ?? "aluguer",
      status: "em_andamento",
      valorTotal,
      valorProprietario: Math.round(valorTotal * 0.7 * 100) / 100,
      valorSistema: Math.round(valorTotal * 0.3 * 100) / 100,
      proprietarioId: data.proprietarioId ?? "",
    });
  },
  update: servicosDB.update,
  remove: servicosDB.remove,
  exists: () => false,
};

