import type { AppUser } from "../types";

export type LoginResult = { ok: boolean; user?: AppUser; error?: string };

// Simple localStorage-based auth shim for local development / demo mode
export async function firebaseLogin(email: string, password: string): Promise<LoginResult> {
  // In this demo shim we don't validate password; just create or reuse a demo uid
  const uid = localStorage.getItem("demo_user_uid") ?? `u${Date.now()}`;
  localStorage.setItem("demo_user_uid", uid);
  localStorage.setItem("current_user_uid", uid);
  const user: AppUser = { uid, email, role: "usuario" } as AppUser;
  return { ok: true, user };
}

export async function firebaseLogout(): Promise<void> {
  localStorage.removeItem("current_user_uid");
}

export type RegisterResult = { ok: boolean; uid?: string; error?: string; user?: AppUser };

export async function firebaseRegister(emailOrData: any, password?: string, nome?: string): Promise<RegisterResult> {
  // Support two call styles: firebaseRegister(email, password, nome?)
  // or firebaseRegister({ email, password, nome, role, extra })
  let email = "";
  let pw = password ?? "";
  let displayName = nome ?? "";
  let role: any = "usuario";
  if (typeof emailOrData === "object") {
    email = emailOrData.email ?? "";
    pw = emailOrData.password ?? pw;
    displayName = emailOrData.nome ?? displayName;
    role = emailOrData.role ?? role;
  } else {
    email = emailOrData ?? "";
  }

  const uid = `u${Date.now()}`;
  localStorage.setItem("demo_user_uid", uid);
  localStorage.setItem("current_user_uid", uid);
  if (displayName) localStorage.setItem(`user_name_${uid}`, displayName);
  const user: AppUser = { uid, email, nome: displayName, role } as AppUser;
  return { ok: true, uid, user };
}

export async function resetPassword(email: string): Promise<{ ok: boolean; error?: string }> {
  // demo: pretend it worked
  return { ok: true };
}

export async function getUserProfile(uid?: string): Promise<AppUser | null> {
  if (!uid) return null;
  const nome = localStorage.getItem(`user_name_${uid}`) ?? "";
  return { uid, email: "", nome, role: "usuario" } as AppUser;
}

export function onAuthStateChange(cb: (user: any) => void) {
  // Call immediately with current user (if present)
  const uid = localStorage.getItem("current_user_uid");
  const user = uid ? { uid } : null;
  setTimeout(() => cb(user), 0);
  // Return unsubscribe
  return () => { /* noop */ };
}
